head.script:
{
  "schemaVersion": "1.0.0",
  "defaultOwner": "registry",
  "defaultSourceLocale": "en",
  "namespacePolicy": {
    "global": {
      "owner": "registry",
      "surface": ["all"],
      "primitive": "system",
      "type": "generic"
    },
    "lang": {
      "owner": "registry",
      "surface": ["all"],
      "primitive": "language-switcher",
      "type": "label"
    },
    "nav": {
      "owner": "registry",
      "surface": ["all"],
      "primitive": "navigation",
      "type": "label"
    },
    "special": {
      "owner": "registry",
      "surface": ["special"],
      "primitive": "special-page",
      "type": "mixed"
    },
    "dock": {
      "owner": "registry",
      "surface": ["listing", "post", "page", "special"],
      "primitive": "dock",
      "type": "label"
    },
    "drawer.more": {
      "owner": "registry",
      "surface": ["listing", "landing", "post", "page", "special"],
      "primitive": "sheet",
      "type": "label"
    },
    "search": {
      "owner": "registry",
      "surface": ["listing", "error", "special"],
      "primitive": "search",
      "type": "mixed"
    },
    "palette": {
      "owner": "registry",
      "surface": ["listing", "post", "page", "special"],
      "primitive": "command-palette",
      "type": "mixed"
    },
    "post.action": {
      "owner": "registry",
      "surface": ["listing", "post"],
      "primitive": "toolbar",
      "type": "action"
    },
    "library": {
      "owner": "registry",
      "surface": ["special", "post", "listing"],
      "primitive": "library",
      "type": "mixed"
    },
    "share": {
      "owner": "registry",
      "surface": ["post", "listing"],
      "primitive": "sheet",
      "type": "mixed"
    },
    "comments": {
      "owner": "registry",
      "surface": ["post", "listing"],
      "primitive": "comments",
      "type": "mixed"
    },
    "toc": {
      "owner": "registry",
      "surface": ["post", "page"],
      "primitive": "panel",
      "type": "mixed"
    },
    "mixed": {
      "owner": "registry",
      "surface": ["listing"],
      "primitive": "mixed-media",
      "type": "mixed"
    },
    "dialog.confirm": {
      "owner": "registry",
      "surface": ["all"],
      "primitive": "dialog",
      "type": "confirm"
    },
    "dialog.delete": {
      "owner": "registry",
      "surface": ["all"],
      "primitive": "dialog",
      "type": "destructive-confirm"
    },
    "toast": {
      "owner": "registry",
      "surface": ["all"],
      "primitive": "toast",
      "type": "status"
    },
    "banner": {
      "owner": "registry",
      "surface": ["all"],
      "primitive": "banner",
      "type": "status"
    },
    "update": {
      "owner": "registry",
      "surface": ["all"],
      "primitive": "update-flow",
      "type": "status"
    },
    "offline": {
      "owner": "registry",
      "surface": ["offline", "all"],
      "primitive": "recovery",
      "type": "status"
    },
    "notfound": {
      "owner": "registry",
      "surface": ["error"],
      "primitive": "error-surface",
      "type": "mixed"
    },
    "install": {
      "owner": "registry",
      "surface": ["landing", "listing", "post", "special"],
      "primitive": "install-prompt",
      "type": "mixed"
    }
  },
  "overrides": {
    "search.input.label": {
      "type": "aria",
      "maxLength": {
        "en": 24,
        "id": 28
      }
    },
    "palette.input.label": {
      "type": "aria",
      "maxLength": {
        "en": 24,
        "id": 28
      }
    },
    "comments.panel.toggle": {
      "type": "aria",
      "maxLength": {
        "en": 40,
        "id": 48
      }
    },
    "post.action.toggleComments": {
      "type": "aria",
      "maxLength": {
        "en": 40,
        "id": 48
      }
    },
    "comments.count.one": {
      "type": "counter",
      "interpolation": false
    },
    "comments.count.many": {
      "type": "counter",
      "interpolation": true,
      "requiredPlaceholders": ["count"]
    },
    "comments.count.short.one": {
      "type": "counter-short",
      "interpolation": false
    },
    "comments.count.short.many": {
      "type": "counter-short",
      "interpolation": true,
      "requiredPlaceholders": ["count"]
    },
    "toast.saved": {
      "status": "fallback-only",
      "notes": "Prefer domain-specific toast keys when possible."
    },
    "toast.removed": {
      "status": "fallback-only",
      "notes": "Prefer domain-specific toast keys when possible."
    },
    "lang.current": {
      "status": "runtime-display-label",
      "notes": "Use only for active locale display, not as source-of-truth locale identity."
    },
    "nav.landing": {
      "status": "conditional-public",
      "notes": "Keep only if landing is intentionally exposed in public navigation."
    }
  },
  "nativePassthrough": {
    "blogger": [
      "data:messages.postAComment",
      "data:messages.deleteComment"
    ],
    "browser": [
      "permission prompts",
      "beforeunload prompt",
      "system install prompt",
      "os-level notifications"
    ]
  },
  "forbiddenPatterns": [
    "alert(",
    "confirm(",
    "prompt(",
    "content:\"",
    "content:'"
  ],
  "deprecationPolicy": {
    "allowAliases": true,
    "requireReplacementKey": true,
    "requireRemovalWindow": true
  }
}

head.b:skin:
/* GG_CRITICAL_CSS v1 */
:root{--gg-bg:#fbfbfa;--gg-surface:#fff;--gg-ink:#0b0d10;--gg-border:rgba(11,13,16,.1);}
*{box-sizing:border-box;}
html,body{height:100%;}
body{margin:0;background:var(--gg-bg);color:var(--gg-ink);font-family:ui-sans-serif,system-ui,-apple-system,"Segoe UI",Roboto,Arial;}
[hidden]{display:none!important;}
img{max-width:100%;height:auto;}
:root{--gg-main-max:1285px;--gg-reading-max:760px;--gg-font-ui:ui-sans-serif,-apple-system,BlinkMacSystemFont,"SF Pro Text","Segoe UI",Roboto,Arial,Segoe UI Emoji,sans-serif;--gg-font-ed:"Newsreader",ui-serif,Georgia,Cambria,"Times New Roman",serif;}
html{ box-sizing:border-box; }
*,*::before,*::after{ box-sizing:inherit; }
body{
  margin:0;
  line-height:1.5;
  text-rendering:optimizeLegibility;
  -webkit-font-smoothing:antialiased;
  font-family:var(--gg-font-ui);
  font-size:16px;
}
a{ color:inherit; text-decoration:none; }
.gg-post__body a, .gg-article a{ text-decoration:underline; text-underline-offset:0.12em; }
.gg-page-shell{ min-height:100%; }
.gg-wrap{ width:min(var(--gg-main-max, 1285px), calc(100% - 32px)); margin-inline:auto; }
.gg-header{ min-height:56px; }

body[data-gg-surface="listing"] .gg-home-landing,
body[data-gg-surface="page"] .gg-home-landing,
body[data-gg-surface="post"] .gg-home-landing{
  display:none !important;
}
body[data-gg-surface="landing"] .gg-home-landing{ display:block; }

:where(a, button, input, textarea, select, summary, [role="button"], [tabindex]):focus-visible{
  outline:2px solid currentColor;
  outline-offset:3px;
}

.gg-skip-link,
.gg-skiplink{
  position:absolute;
  top:0;
  left:-999px;
  padding:10px 12px;
  background:Canvas;
  color:CanvasText;
  border:1px solid currentColor;
  z-index:9999;
  text-decoration:none;
}
.gg-skip-link:focus,
.gg-skiplink:focus{
  left:var(--gg-space-16, 16px);
  top:var(--gg-space-16, 16px);
}
.gg-site-title, h1, h2, h3{
  font-family: var(--gg-font-ed);
  letter-spacing: -0.015em;
  font-weight: 600;
}
@media (prefers-reduced-motion: reduce){
  html{ scroll-behavior:auto; }
}

.gg-listing__title{
  font-family: 'Caesar Dressing', cursive;
  font-weight: 600;
  letter-spacing: -0.02em;
  line-height: 1.06;
  text-wrap: balance;
  text-align: center;
font-size: xxx-large;
margin-top: 10px;
margin-bottom: 25px;
}

.gg-listing__subtitle{
  font-family: var(--gg-font-ed);
  font-weight: 450;
  letter-spacing: 0.200em;
  line-height: 0;
  text-wrap: balance;
font-size: medium;
    text-align: center;
    margin-bottom: 20px;
    text-transform: uppercase;
    margin-top: -15px;
}
